template <typename LaunchFunc>
static double timed_cuda_launch(LaunchFunc&& launch, bool use_os_timer) {
    if (use_os_timer) {
        auto ts_start = std::chrono::high_resolution_clock::now();
        launch();
        CUDA_SAFE_CALL(cudaPeekAtLastError());
        CUDA_SAFE_CALL(cudaDeviceSynchronize());
        auto ts_end = std::chrono::high_resolution_clock::now();
        return std::chrono::duration<double, std::milli>(ts_end - ts_start).count();
    } else {
        cudaEvent_t ev_start, ev_stop;
        CUDA_SAFE_CALL(cudaEventCreate(&ev_start));
        CUDA_SAFE_CALL(cudaEventCreate(&ev_stop));
        CUDA_SAFE_CALL(cudaEventRecord(ev_start, 0));
        launch();
        CUDA_SAFE_CALL(cudaPeekAtLastError());
        CUDA_SAFE_CALL(cudaEventRecord(ev_stop, 0));
        CUDA_SAFE_CALL(cudaEventSynchronize(ev_stop));
        float elapsed_ms = 0.0f;
        CUDA_SAFE_CALL(cudaEventElapsedTime(&elapsed_ms, ev_start, ev_stop));
        CUDA_SAFE_CALL(cudaEventDestroy(ev_start));
        CUDA_SAFE_CALL(cudaEventDestroy(ev_stop));
        return (double)elapsed_ms;
    }
}

template <bool BLOCK_STRIDED, int ELEMENTS_PER_THREAD, int FUSION_DEGREE>
static void runbench(const int compute_iterations_arr[],
                     unsigned int krn_idx,
                     void* cbuffer,
                     long size,
                     size_t workgroupsize,
                     bool enable_dp,
                     bool enable_hp,
                     bool use_os_timer) {
    const long compute_grid_size = size / ELEMENTS_PER_THREAD / FUSION_DEGREE;
    const int current_compute_iterations = compute_iterations_arr[krn_idx];
    const long long computations =
        (ELEMENTS_PER_THREAD * (long long)compute_grid_size +
         (2LL * ELEMENTS_PER_THREAD * current_compute_iterations) *
             (long long)compute_grid_size) *
        FUSION_DEGREE;
    const long long memoryoperations = size;

    const dim3 block((unsigned int)workgroupsize);
    const dim3 grid((unsigned int)(compute_grid_size / (long)workgroupsize));

    constexpr int total_bench_iterations = 3;

    double kernel_time_mad_sp = benchmark_average<total_bench_iterations>([&]() {
        const float seed_f = 1.0f;
        return timed_cuda_launch([&]() {
            dispatch_benchmark_kernel<float, BLOCK_STRIDED, ELEMENTS_PER_THREAD, FUSION_DEGREE>(
                current_compute_iterations, grid, block, seed_f, (float*)cbuffer, compute_grid_size);
        }, use_os_timer);
    });

    double kernel_time_mad_dp = benchmark_average<total_bench_iterations>([&]() {
        const double seed_d = 1.0;
        if (enable_dp) {
            return timed_cuda_launch([&]() {
                dispatch_benchmark_kernel<double, BLOCK_STRIDED, ELEMENTS_PER_THREAD, FUSION_DEGREE>(
                    current_compute_iterations, grid, block, seed_d, (double*)cbuffer, compute_grid_size);
            }, use_os_timer);
        } else {
            return 0.0;
        }
    });

    double kernel_time_mad_hp = benchmark_average<total_bench_iterations>([&]() {
        const __half2 seed_h = __float2half2_rn(1.0f);
        if (enable_hp) {
            return timed_cuda_launch([&]() {
                dispatch_benchmark_kernel<__half2, BLOCK_STRIDED, ELEMENTS_PER_THREAD, FUSION_DEGREE>(
                    current_compute_iterations, grid, block, seed_h, (__half2*)cbuffer, compute_grid_size);
            }, use_os_timer);
        } else {
            return 0.0;
        }
    });

    double kernel_time_mad_int = benchmark_average<total_bench_iterations>([&]() {
        const int seed_i = 1;
        return timed_cuda_launch([&]() {
            dispatch_benchmark_kernel<int, BLOCK_STRIDED, ELEMENTS_PER_THREAD, FUSION_DEGREE>(
                current_compute_iterations, grid, block, seed_i, (int*)cbuffer, compute_grid_size);
        }, use_os_timer);
    });

    printf(
        "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
        "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
        current_compute_iterations,
        ((double)computations) / ((double)memoryoperations * sizeof(float)),
        kernel_time_mad_sp,
        ((double)computations) / kernel_time_mad_sp * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
            (1000. * 1000. * 1000.),
        ((double)computations) / ((double)memoryoperations * sizeof(double)),
        kernel_time_mad_dp,
        ((double)computations) / kernel_time_mad_dp * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
            (1000. * 1000. * 1000.),
        ((double)2 * computations) /
            ((double)memoryoperations * sizeof(__half2)),
        kernel_time_mad_hp,
        ((double)2 * computations) / kernel_time_mad_hp * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(__half2)) / kernel_time_mad_hp *
            1000. / (1000. * 1000. * 1000.),
        ((double)computations) / ((double)memoryoperations * sizeof(int)),
        kernel_time_mad_int,
        ((double)computations) / kernel_time_mad_int * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
            (1000. * 1000. * 1000.));
}

extern "C" void mixbenchGPU(double* c, long size) {
    const bool block_strided = false;
    const bool host_allocated = false;
    const bool use_os_timer = false;
    const size_t workgroupsize = 256;
    const unsigned int elements_per_wi = 8;
    const unsigned int fusion_degree = 4;

    printf("Workgroup size:         %zu\n", workgroupsize);
    printf("Elements per workitem:  %u\n", elements_per_wi);
    printf("Workitem fusion degree: %u\n", fusion_degree);

    const char* benchtype = block_strided ? "Workgroup" : "NDRange";
    printf("Workitem stride:        %s\n", benchtype);
    const char* buffer_allocation =
        host_allocated ? "Host allocated" : "Device allocated";
    printf("Buffer allocation:      %s\n", buffer_allocation);
    printf("Timer:                  %s\n",
           use_os_timer ? "OS based" : "CL event based");

    cudaDeviceProp deviceProp = GetDeviceProperties();
    bool enable_dp = (deviceProp.major > 1) || (deviceProp.major == 1 && deviceProp.minor >= 3);
    if (!enable_dp)
        printf(
            "Warning:                Double precision computations are not "
            "supported\n");
    bool enable_hp = IsFP16Supported();
    if (!enable_hp)
        printf(
            "Warning:                Half precision computations are not "
            "supported\n");

    if ((size_t)deviceProp.maxThreadsPerBlock < workgroupsize) {
        fprintf(stderr, "Error: Unsupported workgroup size (%u).\n", (unsigned int)workgroupsize);
        exit(1);
    }

    const long compute_grid_size = size / (long)elements_per_wi / (long)fusion_degree;
    if (compute_grid_size % (long)workgroupsize != 0) {
        fprintf(stderr, "Error: Unsupported workgroup size (%u).\n", (unsigned int)workgroupsize);
        exit(1);
    }

    void* c_buffer = nullptr;
    CUDA_SAFE_CALL(cudaMalloc(&c_buffer, (size_t)size * sizeof(double)));

    CUDA_SAFE_CALL(cudaMemset(c_buffer, 0, (size_t)size * sizeof(int)));

    printf("Loading kernel source file...\n");
    printf("Precompilation of kernels... ");
    show_progress_init(compute_iterations_len);
    for (int i = 0; i < compute_iterations_len; i++) {
        show_progress_step(0, '\\');
        show_progress_step(0, '|');
        if (enable_dp) show_progress_step(0, '/');
        if (enable_hp) show_progress_step(0, '-');
        show_progress_step(1, '>');
    }
    show_progress_done();

    {
        const long reduced_grid_size = size / 256;
        dim3 block((unsigned int)workgroupsize);
        dim3 grid((unsigned int)FRACTION_CEILING(reduced_grid_size, (long)workgroupsize));
        const short seed = 1;
        benchmark_kernel<short, 0, false, 1, 1><<<grid, block>>>(
            seed, (short*)c_buffer, reduced_grid_size);
        CUDA_SAFE_CALL(cudaPeekAtLastError());
    }

    CUDA_SAFE_CALL(cudaDeviceSynchronize());

    printf(
        "------------------------------------------------------------------------"
        "----- CSV data "
        "------------------------------------------------------------------------"
        "-----\n");
    printf(
        "Experiment ID, Single Precision ops,,,,              Double precision "
        "ops,,,,              Half precision ops,,,,                Integer "
        "operations,,, \n");
    printf(
        "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, "
        "ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
        "Iops/byte, ex.time,   GIOPS, GB/sec\n");

    for (int i = 0; i < compute_iterations_len; i++) {
        runbench<false, 8, 4>(compute_iterations, i, c_buffer, size,
                              workgroupsize, enable_dp, enable_hp, use_os_timer);
    }

    printf(
        "------------------------------------------------------------------------"
        "------------------------------------------------------------------------"
        "--------------------\n");

    CUDA_SAFE_CALL(cudaMemcpy(c, c_buffer, (size_t)size * sizeof(double),
                              cudaMemcpyDeviceToHost));

    CUDA_SAFE_CALL(cudaFree(c_buffer));
}
